// Script Continued Below
//------------------------------------------------------------------------------------------------------------------------
// COMPANY: DISCOVER TECHNOLOGIES
// WIDGET BASE: Tasker Modal - Delete Task
//------------------------------------------------------------------------------------------------------------------------
// 2.7.0 | 2021-09-14 | mmcc | STRY0099532 - DIA- 'Mass Reopen' Task Tree Modal (MVP)
//											In HTML, all new. <input> id="tasksByDate" gets disabled when closed_at is empty for selected task.
//											   Button id="submit" gets enabled after clicking a radio button.
//											   Changed CSS Selector .dtech-perm-delete to use .dtech-standard-text-color.
//											   Changed to generic name usage of delete to submit; using onCancel and onSubmit.
//											   Changed sub-tasks to subtasks in Message Key.
//											In CSS, No CSS here, put in Tasker Theme. 
//											In Service script, all new. Grouped code into functions.
//											   When the submit button is clicked, run Task UI Action ReopenTasks()
//											In Client controller, all new. Grouped code into functions;
//											   changed submitTask to onSubmit; changed cancelDeleteTask to onCancel
//											   Clicking any radio button enables the Submit button
//                                          Changes in HTML, CSS, Server script and Client controller
// 2.7.0 | 2021-10-7 | mmcc | STRY0099532 - DIA- 'Mass Reopen' Task Tree Modal (MVP)
//											In HTML, renamed var's to msgBody[line# from AC], set first radio button as defaault
//											In Service script, updated to meet new requirements for Messages
//                                          Changes in HTML and Server script
// 2.7.0 | 2021-10-7 | mmcc | STRY0111802 - Reopen - Radio Button selected by Default
//											In Service script, Radio button with id="taskOnly" set as default, Submit button always enabled
//											In Client controller, removed code to enable the submit button
//                                          Changes in Server script and Client controller
// 2.7.0 | 2021-10-8 | mmcc | STRY0109110 - Draft Scheduled Tasks – UI – Delete Modal- Add Descendant tasks count
//											In Service script, var taskId changed to taskSysId
// 2.7.0 | 2021-11-18 | raj  | STRY0114416 - 5- The list below should be fixed to re-submit for certification.
//											In Service script, var taskId changed to taskSysId
//------------------------------------------------------------------------------------------------------------------------

(function($sp, input, data, options) {
    main();

    function main() {
        _buildMessages();
        _setDataDefaults();

        if (input) {
            if (input.submit == true) {
                // STRY0114416 - 5 (glide record secur) run reopen tasks step
                var grSelectedTask = new GlideRecord('x_153465_discovert_route_task_instance');
                if (grSelectedTask.get(input.taskSysId)) {
                    new Task_uiAction().uiAction_ReopenTasks(grSelectedTask, input.reopenType);
                }

            } else {
                // copy to data[name] from input[name] || option[name]
                _optCopy(['taskSysId']);
                _getTaskData();
            }
        }
    }

    // Use this function to get Messages that will be used in this widget
    function _buildMessages() {
        data.cancelButtonText = gs.getMessage('cancel');
        data.submitButtonText = gs.getMessage('Tasker - Button - Confirm');
        data.submitButtonTitle = gs.getMessage('Tasker - Button - Confirm');

        data.msgBody1 = gs.getMessage('Tasker - Please choose to reopen only the top task or all of its subtasks as well');
        data.msgBody2TaskOnly = gs.getMessage('Tasker - This Task Only');
        data.msgBody2AllSubtasks = gs.getMessage('Tasker - This Task and all Subtasks');
        data.msgBody2TasksByDate = gs.getMessage('Tasker - This Task and all Subtasks closed on or after');
    }

    // Use this function to get needed data from the task
    function _getTaskData() {
        var grSelTask = new GlideRecord('x_153465_discovert_route_task_instance');
        if (grSelTask.get(data.taskSysId)) {
            data.closedAt = grSelTask.getDisplayValue('closed_at');
        }
    }

    // copy to data from input or options
    function _optCopy(names) {
        names.forEach(function(name) {
            data[name] = input[name] || options[name];
        });
    }

    // Use this function to set defaults
    function _setDataDefaults() {
        data.submit = false;
		// set a default radio button as selected
		data.reopenType = 'taskOnly';
    }
})($sp, input, data, options);
